//! Argon CLI Integration Tests

use assert_cmd::cargo::cargo_bin_cmd;
use predicates::prelude::*;
use std::fs;
use std::path::PathBuf;
use std::process::Command;

#[allow(dead_code)]
fn test_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
}

fn repo_root() -> PathBuf {
    test_dir().join("..").join("..")
}

fn examples_dir() -> PathBuf {
    repo_root().join("examples")
}

fn assert_real_native_wasm(output_file: &PathBuf) {
    let wat = fs::read_to_string(output_file.with_extension("wat")).unwrap();
    assert!(
        wat.contains("(func"),
        "expected native wasm function body, got:\n{wat}"
    );
}

#[test]
fn test_compile_simple() {
    let temp_dir = tempfile::tempdir().unwrap();
    let source_file = temp_dir.path().join("test.arg");
    fs::write(&source_file, "const x = 5;\nconsole.log(x);\n").unwrap();

    let mut cmd = cargo_bin_cmd!("argon");
    cmd.arg("compile")
        .arg(&source_file)
        .arg("-o")
        .arg(temp_dir.path().join("output.js"))
        .arg("--pipeline")
        .arg("ir")
        .assert()
        .success()
        .stdout(predicate::str::contains("Parsing"))
        .stdout(predicate::str::contains("Type checking"))
        .stdout(predicate::str::contains("Borrow checking"))
        .stdout(predicate::str::contains("Generating JavaScript"))
        .stdout(predicate::str::contains("Done"));

    let output = fs::read_to_string(temp_dir.path().join("output.js")).unwrap();
    assert!(output.contains("Generated by Argon (IR)"));
    assert!(output.contains("const x = 5"));
    assert!(output.contains("console.log(x)"));
}

#[test]
fn test_compile_writes_source_map_when_enabled() {
    let temp_dir = tempfile::tempdir().unwrap();
    let source_file = temp_dir.path().join("sourcemap.arg");
    fs::write(&source_file, "const x = 5;\nconsole.log(x);\n").unwrap();

    let output_js = temp_dir.path().join("output.js");
    let output_map = temp_dir.path().join("output.js.map");

    let mut cmd = cargo_bin_cmd!("argon");
    cmd.arg("compile")
        .arg(&source_file)
        .arg("-o")
        .arg(&output_js)
        .arg("--pipeline")
        .arg("ir")
        .arg("--source-map")
        .assert()
        .success();

    let js = fs::read_to_string(&output_js).unwrap();
    assert!(js.contains("sourceMappingURL=output.js.map"));

    let map = fs::read_to_string(&output_map).unwrap();
    assert!(map.contains("\"version\":3"));
}

#[test]
fn test_compile_try_catch_finally() {
    let temp_dir = tempfile::tempdir().unwrap();
    let source_file = temp_dir.path().join("try.arg");
    fs::write(
        &source_file,
        "function f(): void { try { const x = 1; throw x; } catch (e) { const y = e; } finally { const z = 3; } }\nf();\n",
    )
    .unwrap();

    let mut cmd = cargo_bin_cmd!("argon");
    cmd.arg("compile")
        .arg(&source_file)
        .arg("-o")
        .arg(temp_dir.path().join("output.js"))
        .arg("--pipeline")
        .arg("ir")
        .assert()
        .success();

    let output = fs::read_to_string(temp_dir.path().join("output.js")).unwrap();
    assert!(output.contains("try {"));
    assert!(output.contains("catch (e)"));
    assert!(output.contains("finally {"));
    assert!(output.contains("throw x"));
}

