#[test]
fn test_compile_wasm_subset_and_execute() {
    let temp_dir = tempfile::tempdir().unwrap();
    let source_file = temp_dir.path().join("subset.arg");
    let output_file = temp_dir.path().join("subset.wasm");
    fs::write(
        &source_file,
        r#"
function sumTo(n: i32): i32 {
    let acc = 0;
    let i = 0;
    while (i <= n) {
        acc = acc + i;
        i = i + 1;
    }
    return acc;
}
"#,
    )
    .unwrap();

    let mut cmd = cargo_bin_cmd!("argon");
    cmd.arg("compile")
        .arg(&source_file)
        .arg("-o")
        .arg(&output_file)
        .arg("--target")
        .arg("wasm")
        .arg("--pipeline")
        .arg("ir")
        .assert()
        .success()
        .stdout(predicate::str::contains("Generating WebAssembly"));

    assert_real_native_wasm(&output_file);

    let script = r#"
const fs = require('fs');
const wasmPath = process.argv[1];
const bytes = fs.readFileSync(wasmPath);
WebAssembly.instantiate(bytes, {}).then(({ instance }) => {
  console.log(String(instance.exports.sumTo(5)));
}).catch((err) => {
  console.error(err);
  process.exit(1);
});
"#;
    let node_output = Command::new("node")
        .arg("-e")
        .arg(script)
        .arg(&output_file)
        .output()
        .unwrap();
    assert!(node_output.status.success());
    let stdout = String::from_utf8_lossy(&node_output.stdout);
    assert!(stdout.contains("15"));
}

#[test]
fn test_compile_wasm_writes_loader_sidecar() {
    let temp_dir = tempfile::tempdir().unwrap();
    let source_file = temp_dir.path().join("loader.arg");
    let output_file = temp_dir.path().join("loader.wasm");
    fs::write(
        &source_file,
        r#"
function greet(): string {
    return "hello";
}
"#,
    )
    .unwrap();

    let mut cmd = cargo_bin_cmd!("argon");
    cmd.arg("compile")
        .arg(&source_file)
        .arg("-o")
        .arg(&output_file)
        .arg("--target")
        .arg("wasm")
        .arg("--pipeline")
        .arg("ir")
        .assert()
        .success();

    let loader_file = output_file.with_extension("mjs");
    let host_file = output_file.with_extension("host.mjs");
    let loader_contents = fs::read_to_string(&loader_file).unwrap();
    assert!(host_file.exists());
    assert!(loader_contents.contains("instantiateArgon"));
    assert!(loader_contents.contains("loader.wasm"));
    assert!(loader_contents.contains("loader.host.mjs"));

    let script_file = temp_dir.path().join("check_loader.mjs");
    fs::write(
        &script_file,
        r#"
import { instantiateArgon } from "./loader.mjs";

const runtime = await instantiateArgon();
console.log(runtime.readString(runtime.exports.greet()));
"#,
    )
    .unwrap();

    let node_output = Command::new("node").arg(&script_file).output().unwrap();
    assert!(node_output.status.success(), "{:?}", node_output);
    let stdout = String::from_utf8_lossy(&node_output.stdout);
    assert!(stdout.contains("hello"));
}

